     1→// ============================================================================
     2→// VM: Virtual Machine - 바이트코드 실행 엔진 with GC
     3→// ============================================================================
     4→
     5→use crate::bytecode::Bytecode;
     6→use crate::opcode::OpCode;
     7→use crate::value::Value;
     8→use crate::gc_object::{ObjectHeap, GcData};
     9→use std::collections::HashMap;
    10→
    11→/// 가상 머신 with GC
    12→pub struct VM {
    13→    bytecode: Bytecode,
    14→    stack: Vec<Value>,
    15→    ip: usize, // Instruction Pointer
    16→    heap: ObjectHeap, // GC 힙
    17→}
    18→
    19→impl VM {
    20→    /// 새로운 VM 생성
    21→    pub fn new(bytecode: Bytecode) -> Self {
    22→        VM {
    23→            bytecode,
    24→            stack: Vec::with_capacity(256),
    25→            ip: 0,
    26→            heap: ObjectHeap::new(),
    27→        }
    28→    }
    29→
    30→    /// 새로운 VM 생성 (커스텀 GC 임계값)
    31→    pub fn with_gc_threshold(bytecode: Bytecode, threshold: usize) -> Self {
    32→        VM {
    33→            bytecode,
    34→            stack: Vec::with_capacity(256),
    35→            ip: 0,
    36→            heap: ObjectHeap::with_threshold(threshold),
    37→        }
    38→    }
    39→
    40→    /// 바이트코드 실행
    41→    pub fn run(&mut self) -> Result<Value, String> {
    42→        while self.ip < self.bytecode.instructions.len() {
    43→            let op_byte = self.bytecode.instructions[self.ip];
    44→            self.ip += 1;
    45→
    46→            let op = OpCode::from_byte(op_byte).ok_or(format!("Unknown opcode: {}", op_byte))?;
    47→
    48→            match op {
    49→                OpCode::OpConstant => {
    50→                    let idx = self.read_u16() as usize;
    51→                    let val = self
    52→                        .bytecode
    53→                        .get_constant(idx)
    54→                        .ok_or(format!("Constant index out of bounds: {}", idx))?;
    55→                    self.stack.push(Value::Int(val));
    56→                }
    57→
    58→                OpCode::OpAdd => {
    59→                    let right = self.stack_pop()?;
    60→                    let left = self.stack_pop()?;
    61→                    match (left, right) {
    62→                        (Value::Int(l), Value::Int(r)) => {
    63→                            self.stack.push(Value::Int(l + r));
    64→                        }
    65→                        _ => return Err("Cannot add non-integers".to_string()),
    66→                    }
    67→                }
    68→
    69→                OpCode::OpSub => {
    70→                    let right = self.stack_pop()?;
    71→                    let left = self.stack_pop()?;
    72→                    match (left, right) {
    73→                        (Value::Int(l), Value::Int(r)) => {
    74→                            self.stack.push(Value::Int(l - r));
    75→                        }
    76→                        _ => return Err("Cannot subtract non-integers".to_string()),
    77→                    }
    78→                }
    79→
    80→                OpCode::OpMul => {
    81→                    let right = self.stack_pop()?;
    82→                    let left = self.stack_pop()?;
    83→                    match (left, right) {
    84→                        (Value::Int(l), Value::Int(r)) => {
    85→                            self.stack.push(Value::Int(l * r));
    86→                        }
    87→                        _ => return Err("Cannot multiply non-integers".to_string()),
    88→                    }
    89→                }
    90→
    91→                OpCode::OpDiv => {
    92→                    let right = self.stack_pop()?;
    93→                    let left = self.stack_pop()?;
    94→                    match (left, right) {
    95→                        (Value::Int(l), Value::Int(r)) => {
    96→                            if r == 0 {
    97→                                return Err("Division by zero".to_string());
    98→                            }
    99→                            self.stack.push(Value::Int(l / r));
   100→                        }
   101→                        _ => return Err("Cannot divide non-integers".to_string()),
   102→                    }
   103→                }
   104→
   105→                OpCode::OpTrue => {
   106→                    self.stack.push(Value::Bool(true));
   107→                }
   108→
   109→                OpCode::OpFalse => {
   110→                    self.stack.push(Value::Bool(false));
   111→                }
   112→
   113→                OpCode::OpEqual => {
   114→                    let right = self.stack_pop()?;
   115→                    let left = self.stack_pop()?;
   116→                    self.stack.push(Value::Bool(left == right));
   117→                }
   118→
   119→                OpCode::OpNotEqual => {
   120→                    let right = self.stack_pop()?;
   121→                    let left = self.stack_pop()?;
   122→                    self.stack.push(Value::Bool(left != right));
   123→                }
   124→
   125→                OpCode::OpLessThan => {
   126→                    let right = self.stack_pop()?;
   127→                    let left = self.stack_pop()?;
   128→                    match (left, right) {
   129→                        (Value::Int(l), Value::Int(r)) => {
   130→                            self.stack.push(Value::Bool(l < r));
   131→                        }
   132→                        _ => return Err("Cannot compare non-integers".to_string()),
   133→                    }
   134→                }
   135→
   136→                OpCode::OpGreaterThanOrEqual => {
   137→                    let right = self.stack_pop()?;
   138→                    let left = self.stack_pop()?;
   139→                    match (left, right) {
   140→                        (Value::Int(l), Value::Int(r)) => {
   141→                            self.stack.push(Value::Bool(l >= r));
   142→                        }
   143→                        _ => return Err("Cannot compare non-integers".to_string()),
   144→                    }
   145→                }
   146→
   147→                OpCode::OpBang => {
   148→                    let val = self.stack_pop()?;
   149→                    self.stack.push(Value::Bool(!val.is_truthy()));
   150→                }
   151→
   152→                OpCode::OpMinus => {
   153→                    let val = self.stack_pop()?;
   154→                    match val {
   155→                        Value::Int(n) => self.stack.push(Value::Int(-n)),
   156→                        _ => return Err("Cannot negate non-integer".to_string()),
   157→                    }
   158→                }
   159→
   160→                OpCode::OpJump => {
   161→                    let target = self.read_u16() as usize;
   162→                    self.ip = target;
   163→                }
   164→
   165→                OpCode::OpJumpNotTruthy => {
   166→                    let target = self.read_u16() as usize;
   167→                    let cond = self.stack_pop()?;
   168→                    if !cond.is_truthy() {
   169→                        self.ip = target;
   170→                    }
   171→                }
   172→
   173→                OpCode::OpNull => {
   174→                    self.stack.push(Value::Null);
   175→                }
   176→
   177→                OpCode::OpPop => {
   178→                    let _ = self.stack_pop()?;
   179→                }
   180→
   181→                OpCode::OpArray => {
   182→                    let count = self.read_u16() as usize;
   183→                    let mut arr = Vec::with_capacity(count);
   184→                    for _ in 0..count {
   185→                        arr.push(self.stack_pop()?);
   186→                    }
   187→                    arr.reverse();
   188→
   189→                    // GC 실행 여부 확인
   190→                    if self.heap.should_collect() {
   191→                        let stats = self.heap.collect_garbage(&self.stack);
   192→                        eprintln!(
   193→                            "[GC #{}: {} → {} ({} freed)]",
   194→                            stats.gc_count, stats.objects_before, stats.objects_after, stats.objects_freed
   195→                        );
   196→                    }
   197→
   198→                    // 배열을 GC 힙에 할당
   199→                    let gc_ref = self.heap.alloc(GcData::Array(arr));
   200→                    self.stack.push(Value::Array(gc_ref));
   201→                }
   202→
   203→                OpCode::OpHash => {
   204→                    let count = self.read_u16() as usize;
   205→                    let mut map = HashMap::new();
   206→                    for _ in 0..count {
   207→                        let val = self.stack_pop()?;
   208→                        let key = match self.stack_pop()? {
   209→                            Value::Int(n) => n.to_string(),
   210→                            _ => return Err("Hash keys must be integers".to_string()),
   211→                        };
   212→                        map.insert(key, val);
   213→                    }
   214→
   215→                    // GC 실행 여부 확인
   216→                    if self.heap.should_collect() {
   217→                        let stats = self.heap.collect_garbage(&self.stack);
   218→                        eprintln!(
   219→                            "[GC #{}: {} → {} ({} freed)]",
   220→                            stats.gc_count, stats.objects_before, stats.objects_after, stats.objects_freed
   221→                        );
   222→                    }
   223→
   224→                    // 해시맵을 GC 힙에 할당
   225→                    let gc_ref = self.heap.alloc(GcData::HashMap(map));
   226→                    self.stack.push(Value::HashMap(gc_ref));
   227→                }
   228→
   229→                OpCode::OpIndex => {
   230→                    let idx = self.stack_pop()?;
   231→                    let container = self.stack_pop()?;
   232→
   233→                    match (container, idx) {
   234→                        (Value::Array(gc_ref), Value::Int(i)) => {
   235→                            // GC 힙에서 배열 조회
   236→                            let obj = self
   237→                                .heap
   238→                                .get(gc_ref)
   239→                                .ok_or(format!("Dangling array reference: {}", gc_ref))?;
   240→
   241→                            match &obj.data {
   242→                                GcData::Array(arr) => {
   243→                                    let idx = if i < 0 {
   244→                                        (arr.len() as i64 + i) as usize
   245→                                    } else {
   246→                                        i as usize
   247→                                    };
   248→
   249→                                    if idx < arr.len() {
   250→                                        self.stack.push(arr[idx].clone());
   251→                                    } else {
   252→                                        self.stack.push(Value::Null);
   253→                                    }
   254→                                }
   255→                                _ => {
   256→                                    return Err(
   257→                                        "Type error: expected array but got different type"
   258→                                            .to_string(),
   259→                                    )
   260→                                }
   261→                            }
   262→                        }
   263→                        (Value::HashMap(gc_ref), key_val) => {
   264→                            // GC 힙에서 해시맵 조회
   265→                            let obj = self
   266→                                .heap
   267→                                .get(gc_ref)
   268→                                .ok_or(format!("Dangling hashmap reference: {}", gc_ref))?;
   269→
   270→                            match &obj.data {
   271→                                GcData::HashMap(map) => {
   272→                                    let key = match key_val {
   273→                                        Value::Int(n) => n.to_string(),
   274→                                        _ => return Err("Hash keys must be integers".to_string()),
   275→                                    };
   276→
   277→                                    match map.get(&key) {
   278→                                        Some(val) => self.stack.push(val.clone()),
   279→                                        None => self.stack.push(Value::Null),
   280→                                    }
   281→                                }
   282→                                _ => {
   283→                                    return Err(
   284→                                        "Type error: expected hashmap but got different type"
   285→                                            .to_string(),
   286→                                    )
   287→                                }
   288→                            }
   289→                        }
   290→                        _ => return Err("Invalid indexing operation".to_string()),
   291→                    }
   292→                }
   293→
   294→                OpCode::OpReturnValue | OpCode::OpReturn => {
   295→                    if let OpCode::OpReturnValue = op {
   296→                        return self.stack_pop();
   297→                    } else {
   298→                        return Ok(Value::Null);
   299→                    }
   300→                }
   301→
   302→                OpCode::OpEnd => {
   303→                    break;
   304→                }
   305→
   306→                _ => return Err(format!("Unimplemented opcode: {:?}", op)),
   307→            }
   308→        }
   309→
   310→        // 스택에 값이 남아있으면 반환
   311→        if !self.stack.is_empty() {
   312→            self.stack_pop()
   313→        } else {
   314→            Ok(Value::Null)
   315→        }
   316→    }
   317→
   318→    /// 스택에서 2바이트 읽기 (Big-Endian)
   319→    fn read_u16(&mut self) -> u16 {
   320→        let high = self.bytecode.instructions[self.ip] as u16;
   321→        let low = self.bytecode.instructions[self.ip + 1] as u16;
   322→        self.ip += 2;
   323→        (high << 8) | low
   324→    }
   325→
   326→    /// 스택에서 값 팝
   327→    fn stack_pop(&mut self) -> Result<Value, String> {
   328→        self.stack.pop().ok_or_else(|| "Stack underflow".to_string())
   329→    }
   330→
   331→    /// 스택의 최상단 값 조회 (팝하지 않음)
   332→    pub fn stack_peek(&self) -> Option<&Value> {
   333→        self.stack.last()
   334→    }
   335→
   336→    /// 스택 상태 확인
   337→    pub fn stack(&self) -> &[Value] {
   338→        &self.stack
   339→    }
   340→
   341→    /// GC 힙 참조
   342→    pub fn heap(&self) -> &ObjectHeap {
   343→        &self.heap
   344→    }
   345→
   346→    /// GC 힙 가변 참조
   347→    pub fn heap_mut(&mut self) -> &mut ObjectHeap {
   348→        &mut self.heap
   349→    }
   350→}
