     8→/// GC 힙에서의 객체 참조 (인덱스)
     9→pub type GcRef = usize;
    10→
    11→/// GC 힙에 저장되는 데이터 종류
    12→#[derive(Debug, Clone)]
    13→pub enum GcData {
    14→    /// 배열
    15→    Array(Vec<Value>),
    16→
    17→    /// 해시맵
    18→    HashMap(HashMap<String, Value>),
    19→
    20→    /// 문자열
    21→    Str(String),
    22→}
    23→
    24→/// GC가 관리하는 힙 객체
    25→#[derive(Debug, Clone)]
    26→pub struct GcObject {
    27→    /// Mark 단계 플래그 (도달 가능 여부 표시)
    28→    pub is_marked: bool,
    29→
    30→    /// 실제 데이터
    31→    pub data: GcData,
    32→}
    33→
    34→impl GcObject {
    35→    /// 새로운 GC 객체 생성
    36→    pub fn new(data: GcData) -> Self {
    37→        GcObject {
    38→            is_marked: false,
    39→            data,
    40→        }
    41→    }
    42→}
    43→
    44→/// GC 실행 통계 (교육용)
    45→#[derive(Debug, Clone, Copy)]
    46→pub struct GcStats {
    47→    /// GC 실행 전 객체 수
    48→    pub objects_before: usize,
    49→
    50→    /// GC 실행 후 객체 수
    51→    pub objects_after: usize,
    52→
    53→    /// 해제된 객체 수
    54→    pub objects_freed: usize,
    55→
    56→    /// 누적 GC 실행 횟수
