    58→}
    59→
    60→/// Arena 패턴 힙 - 모든 GC 객체를 소유
    61→pub struct ObjectHeap {
    62→    /// 객체 슬롯 (None = 해제된 슬롯)
    63→    objects: Vec<Option<GcObject>>,
    64→
    65→    /// 적응형 GC 임계값
    66→    gc_threshold: usize,
    67→
    68→    /// GC 실행 횟수
    69→    gc_count: usize,
    70→}
    71→
    72→impl ObjectHeap {
    73→    /// 새로운 ObjectHeap 생성 (기본 임계값: 64개 객체)
    74→    pub fn new() -> Self {
    75→        ObjectHeap {
    76→            objects: Vec::new(),
    77→            gc_threshold: 64,
    78→            gc_count: 0,
    79→        }
    80→    }
    81→
    82→    /// 커스텀 임계값으로 ObjectHeap 생성
    83→    pub fn with_threshold(threshold: usize) -> Self {
    84→        ObjectHeap {
    85→            objects: Vec::new(),
    86→            gc_threshold: threshold,
    87→            gc_count: 0,
    88→        }
    89→    }
    90→
    91→    /// 객체 할당 (빈 슬롯 재사용 or 새 슬롯 추가)
    92→    pub fn alloc(&mut self, data: GcData) -> GcRef {
    93→        let obj = GcObject::new(data);
    94→
    95→        // 빈 슬롯 찾기
    96→        for (i, slot) in self.objects.iter_mut().enumerate() {
    97→            if slot.is_none() {
    98→                *slot = Some(obj);
    99→                return i;
   100→            }
   101→        }
   102→
   103→        // 빈 슬롯이 없으면 새로 추가
   104→        self.objects.push(Some(obj));
   105→        self.objects.len() - 1
   106→    }
   107→
   108→    /// 객체 불변 조회
   109→    pub fn get(&self, gc_ref: GcRef) -> Option<&GcObject> {
   110→        self.objects.get(gc_ref)?.as_ref()
   111→    }
   112→
   113→    /// 객체 가변 조회
   114→    pub fn get_mut(&mut self, gc_ref: GcRef) -> Option<&mut GcObject> {
   115→        self.objects.get_mut(gc_ref)?.as_mut()
   116→    }
   117→
   118→    /// 살아있는 객체 수 (None이 아닌 슬롯)
   119→    pub fn live_count(&self) -> usize {
   120→        self.objects.iter().filter(|slot| slot.is_some()).count()
   121→    }
   122→
   123→    /// GC 실행 필요 여부
   124→    pub fn should_collect(&self) -> bool {
   125→        self.live_count() >= self.gc_threshold
   126→    }
   127→
   128→    /// 모든 객체의 마킹 플래그 초기화
   129→    fn reset_marks(&mut self) {
   130→        for slot in self.objects.iter_mut() {
   131→            if let Some(obj) = slot {
   132→                obj.is_marked = false;
   133→            }
   134→        }
   135→    }
   136→
   137→    /// Mark 단계: 루트에서 도달 가능한 객체들을 마킹 (worklist DFS)
   138→    pub fn mark(&mut self, roots: &[Value]) {
   139→        self.reset_marks();
   140→
   141→        // 루트에서 시작하는 모든 GcRef를 worklist에 추가
   142→        let mut worklist: Vec<GcRef> = roots
   143→            .iter()
   144→            .filter_map(|v| v.as_gc_ref())
   145→            .collect();
   146→
   147→        // Worklist DFS: 스택을 사용하여 재귀 없이 순회
   148→        while let Some(gc_ref) = worklist.pop() {
   149→            // GcRef가 유효하지 않거나 슬롯이 비었으면 스킵
   150→            if gc_ref >= self.objects.len() {
   151→                continue;
   152→            }
   153→
   154→            let Some(Some(obj)) = self.objects.get_mut(gc_ref) else {
   155→                continue;
   156→            };
   157→
   158→            // 이미 마킹되면 스킵 (순환 참조 처리)
   159→            if obj.is_marked {
   160→                continue;
   161→            }
   162→
   163→            obj.is_marked = true;
   164→
   165→            // 자식 GcRef를 수집
   166→            let children: Vec<GcRef> = match &obj.data {
   167→                GcData::Array(arr) => {
   168→                    arr.iter().filter_map(|v| v.as_gc_ref()).collect()
   169→                }
   170→                GcData::HashMap(map) => {
   171→                    map.values().filter_map(|v| v.as_gc_ref()).collect()
   172→                }
   173→                GcData::Str(_) => vec![],
   174→            };
   175→
   176→            // 자식들을 worklist에 추가
   177→            worklist.extend(children);
   178→        }
   179→    }
   180→
   181→    /// Sweep 단계: 마킹되지 않은 객체들을 해제
   182→    pub fn sweep(&mut self) -> usize {
   183→        let mut freed = 0;
   184→
   185→        for slot in self.objects.iter_mut() {
   186→            match slot {
   187→                Some(obj) if !obj.is_marked => {
   188→                    *slot = None;
   189→                    freed += 1;
   190→                }
   191→                Some(obj) => {
   192→                    // 마킹 플래그 리셋 (다음 GC 준비)
   193→                    obj.is_marked = false;
   194→                }
   195→                None => {}
   196→            }
   197→        }
   198→
   199→        freed
   200→    }
   201→
   202→    /// Mark-and-Sweep GC 실행
   203→    pub fn collect_garbage(&mut self, roots: &[Value]) -> GcStats {
   204→        let objects_before = self.live_count();
   205→
   206→        // Mark 단계
   207→        self.mark(roots);
   208→
   209→        // Sweep 단계
   210→        let objects_freed = self.sweep();
   211→
   212→        let objects_after = self.live_count();
   213→        self.gc_count += 1;
   214→
   215→        GcStats {
   216→            objects_before,
   217→            objects_after,
   218→            objects_freed,
   219→            gc_count: self.gc_count,
   220→        }
   221→    }
   222→
   223→    /// 총 할당된 슬롯 수 (None 포함)
   224→    pub fn capacity(&self) -> usize {
   225→        self.objects.len()
   226→    }
   227→
   228→    /// GC 임계값 변경
   229→    pub fn set_threshold(&mut self, threshold: usize) {
   230→        self.gc_threshold = threshold;
   231→    }
   232→
   233→    /// GC 실행 횟수 조회
   234→    pub fn gc_count(&self) -> usize {
   235→        self.gc_count
   236→    }
   237→}
