   138→fn section_5_mark_phase() {
   139→    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
   140→    println!("Section 5: Mark 단계 - 도달 가능 객체 표시");
   141→    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");
   142→
   143→    let mut heap = ObjectHeap::new();
   144→
   145→    // 객체 생성
   146→    let arr_ref1 = heap.alloc(GcData::Array(vec![]));
   147→    let arr_ref2 = heap.alloc(GcData::Array(vec![]));
   148→    let arr_ref3 = heap.alloc(GcData::Array(vec![]));
   149→
   150→    println!("🌳 Mark 알고리즘 (Worklist DFS):");
   151→    println!("  1. 루트 집합 준비 (스택, 전역, 환경)");
   152→    println!("  2. reset_marks() - 모든 is_marked = false");
   153→    println!("  3. worklist = [루트에서 나온 GcRef들]");
   154→    println!("  4. while worklist not empty:");
   155→    println!("     - ref = worklist.pop()");
   156→    println!("     - if marked: continue");
   157→    println!("     - marked = true");
   158→    println!("     - children = ref의 자식들");
   159→    println!("     - worklist.extend(children)\n");
   160→
   161→    println!("📍 예시: 루트 = [arr_ref1]");
   162→    let roots = vec![Value::Array(arr_ref1)];
   163→    heap.mark(&roots);
   164→
   165→    println!("  마킹 결과:");
   166→    println!("    arr_ref1: {}", heap.get(arr_ref1).unwrap().is_marked);
   167→    println!("    arr_ref2: {}", heap.get(arr_ref2).unwrap().is_marked);
   168→    println!("    arr_ref3: {}\n", heap.get(arr_ref3).unwrap().is_marked);
   169→
   170→    println!("✅ 섹션 완료\n");
   171→}
